package br.com.pueria.pueria.desenvolvimento.infraestrutura.persistencia;
import br.com.pueria.pueria.desenvolvimento.dominio.*; import jakarta.persistence.*; import java.time.LocalDateTime; import java.util.UUID;
@Entity @Table(name="historico_respostas_marcos_desenvolvimento") public class HistoricoRespostaMarcoDesenvolvimentoJpaEntidade { @Id private UUID id; @Column(name="crianca_id") private UUID criancaId; @Column(name="marco_id") private UUID marcoId; @Enumerated(EnumType.STRING) @Column(name="status_anterior") private StatusMarcoDesenvolvimento statusAnterior; @Enumerated(EnumType.STRING) @Column(name="status_novo") private StatusMarcoDesenvolvimento statusNovo; @Column(name="observacao_anterior") private String observacaoAnterior; @Column(name="observacao_nova") private String observacaoNova; @Enumerated(EnumType.STRING) private ModalidadeRegistroMarcoDesenvolvimento modalidade; @Column(name="registrado_em") private LocalDateTime registradoEm; protected HistoricoRespostaMarcoDesenvolvimentoJpaEntidade(){} public HistoricoRespostaMarcoDesenvolvimentoJpaEntidade(HistoricoRespostaMarcoDesenvolvimento h){id=h.id();criancaId=h.criancaId();marcoId=h.marcoId();statusAnterior=h.statusAnterior();statusNovo=h.statusNovo();observacaoAnterior=h.observacaoAnterior();observacaoNova=h.observacaoNova();modalidade=h.modalidade();registradoEm=h.registradoEm();} public UUID getId(){return id;} public UUID getCriancaId(){return criancaId;} public UUID getMarcoId(){return marcoId;} public StatusMarcoDesenvolvimento getStatusAnterior(){return statusAnterior;} public StatusMarcoDesenvolvimento getStatusNovo(){return statusNovo;} public String getObservacaoAnterior(){return observacaoAnterior;} public String getObservacaoNova(){return observacaoNova;} public ModalidadeRegistroMarcoDesenvolvimento getModalidade(){return modalidade;} public LocalDateTime getRegistradoEm(){return registradoEm;} }
